"use client";

import * as React from "react";

import { TeamFeedbackCelebration } from "./parts/team-feedback-celebration";
import { TeamFeedbackLoopRoot } from "./parts/team-feedback-loop-root";
import { TeamFeedbackNudge } from "./parts/team-feedback-nudge";
import type { TeamFeedbackLoop01Props, TeamFeedbackLoopHandle } from "./types";

/**
 * Tier A — the batteries-included assembly: `Root` + `showCelebration`-gated
 * celebration + `showNudge`-gated nudge. Forwards its `ref` straight to `Root`
 * (which owns the imperative handle). Contains **no logic the parts don't** — a
 * hand-assembled layout behaves identically.
 *
 * A host-triggered, NON-BLOCKING (D-10) cooperative feedback layer: a brief (< 1s),
 * skippable celebration + a gentle next-task nudge. Owns no milestone/badge/task
 * data. Team-scoped copy only — never an individual (D-08).
 */
export const TeamFeedbackLoop01 = React.forwardRef<
  TeamFeedbackLoopHandle,
  TeamFeedbackLoop01Props
>(function TeamFeedbackLoop01(
  { showCelebration = true, showNudge = true, ...rootProps },
  ref,
) {
  return (
    <TeamFeedbackLoopRoot ref={ref} {...rootProps}>
      {showCelebration ? <TeamFeedbackCelebration /> : null}
      {showNudge ? <TeamFeedbackNudge /> : null}
    </TeamFeedbackLoopRoot>
  );
});

// Tier A — batteries-included assembly.
export { TeamFeedbackLoop01 } from "./team-feedback-loop-01";

// Tier B — headless provider + flat à-la-carte parts.
export { TeamFeedbackLoopRoot } from "./parts/team-feedback-loop-root";
export { TeamFeedbackCelebration } from "./parts/team-feedback-celebration";
export { TeamFeedbackNudge } from "./parts/team-feedback-nudge";

// Tier C — context-free primitives. ConfettiBurst is the lazy-chunk host; the
// Grid pulls it via React.lazy, so importing it here for standalone use does not
// force it into a default consumer's bundle (unused re-exports tree-shake).
export { CelebrationOverlay } from "./parts/celebration-overlay";
export { NextTaskNudge } from "./parts/next-task-nudge";
export { default as ConfettiBurst } from "./parts/confetti-burst";

// Context consumer for hand-assembled layouts.
export { useTeamFeedbackLoop } from "./hooks/use-team-feedback-context";

// Public types.
export type {
  TeamFeedbackLoop01Props,
  TeamFeedbackLoopRootProps,
  TeamFeedbackLoopBaseProps,
  TeamFeedbackLoopHandle,
  TeamFeedbackContextValue,
  CelebrationOverlayProps,
  NextTaskNudgeProps,
  FeedbackEvent,
  NextTaskSuggestion,
  NudgePlacement,
  GamificationEvent,
} from "./types";

import type { ReactNode } from "react";

/**
 * `team-feedback-loop-01` — public type surface.
 *
 * Framework-free (no `"use client"`): importable from a server component's type
 * position. Per system D-03 every type is **re-declared locally** — this
 * component imports nothing from another registry component. These E6 trigger
 * shapes are intentionally component-local (system §4), not in the shared model.
 */

/** What just happened — drives the celebration. Host-owned; pushed in. */
export interface FeedbackEvent {
  kind: "milestone" | "badge" | "task-complete";
  /** Team-scoped copy ("Your team…"); NEVER an individual (D-08). */
  title: string;
  detail?: string;
  /** Optional progression-loop chapter line (E5 overlap). */
  narrativeBeat?: string;
}

/** What to do next — drives the nudge. Closes the engagement loop. */
export interface NextTaskSuggestion {
  /** Opaque to this component; returned on accept. */
  taskId: string;
  label: string;
}

/**
 * Telemetry slice (D-07 symmetry). **This component emits NOTHING** — the
 * catalogue lists no telemetry event for E6 (C4: accept-but-silent). The prop is
 * accepted for API symmetry; the host types its own envelope.
 */
export type GamificationEvent = { type: string; teamId: string; [key: string]: unknown };

export type NudgePlacement = "inline" | "corner";

/** Data + trigger + callback surface shared by the assembly and the headless `Root`. */
export interface TeamFeedbackLoopBaseProps {
  /** Team identity for team-scoped copy + (if wired) telemetry envelope. Identity-only (D-15). */
  teamId: string;

  // Celebration — controlled trigger (primary, C3).
  /** Set → (re)open the celebration; `null` → close (silently). Omit entirely for imperative-only. */
  event?: FeedbackEvent | null;
  /** Auto-dismiss after N ms. Clamped to [200, 999) (D-10). Default ~800. */
  celebrationDurationMs?: number;
  /** Opt-in lazy confetti for `milestone`/`badge` kinds. Default `false`. */
  enableConfetti?: boolean;
  /** Override the celebration body; the wrapper stays non-blocking regardless. */
  renderCelebration?: (event: FeedbackEvent) => ReactNode;
  /** Fired when the celebration is dismissed by the timer (`auto`) or the user (`skip`). */
  onCelebrationDismiss?: (event: FeedbackEvent, reason: "auto" | "skip") => void;

  // Next-task nudge.
  nextTask?: NextTaskSuggestion;
  onNextTask?: (suggestion: NextTaskSuggestion) => void;
  onNudgeDismiss?: (suggestion: NextTaskSuggestion) => void;
  /** Where the nudge mounts. Default `"inline"`. NEVER modal. */
  nudgePlacement?: NudgePlacement;

  /** Telemetry (D-07) — accepted for symmetry, emits nothing for E6 (C4). */
  onEvent?: (event: GamificationEvent) => void;

  className?: string;
  "aria-label"?: string;
}

/** Props for the batteries-included `TeamFeedbackLoop01` assembly. */
export interface TeamFeedbackLoop01Props extends TeamFeedbackLoopBaseProps {
  /** Render the celebration surface. Default `true`. */
  showCelebration?: boolean;
  /** Render the nudge surface. Default `true`. */
  showNudge?: boolean;
}

/** Props for the headless provider `TeamFeedbackLoopRoot`. */
export interface TeamFeedbackLoopRootProps extends TeamFeedbackLoopBaseProps {
  children: ReactNode;
}

/** Imperative handle (C3 — both trigger paths, controlled-primary). Lives on `Root`. */
export interface TeamFeedbackLoopHandle {
  /** Fire a celebration imperatively → reducer `open`. */
  celebrate(event: FeedbackEvent): void;
  /** Dismiss the current celebration now → reducer `close` (reason `"skip"`). */
  dismiss(): void;
}

/** Props for the context-free Tier-C `CelebrationOverlay`. */
export interface CelebrationOverlayProps {
  event: FeedbackEvent;
  reducedMotion: boolean;
  onSkip: () => void;
  render?: (event: FeedbackEvent) => ReactNode;
  /** Confetti burst slot (rendered inside the non-blocking wrapper). */
  children?: ReactNode;
  className?: string;
}

/** Props for the context-free Tier-C `NextTaskNudge`. */
export interface NextTaskNudgeProps {
  suggestion: NextTaskSuggestion;
  placement?: NudgePlacement;
  onAccept: (suggestion: NextTaskSuggestion) => void;
  onDismiss: (suggestion: NextTaskSuggestion) => void;
  className?: string;
}

/** The resolved state every context part reads — one source of truth. */
export interface TeamFeedbackContextValue {
  current: FeedbackEvent | null;
  reducedMotion: boolean;
  enableConfetti: boolean;
  renderCelebration?: (event: FeedbackEvent) => ReactNode;
  /** Dismiss the celebration now (fires `onCelebrationDismiss(event, "skip")`). */
  skip: () => void;
  /** The visible nudge (null when unset or dismissed). */
  nudge: NextTaskSuggestion | null;
  nudgePlacement: NudgePlacement;
  acceptNudge: (suggestion: NextTaskSuggestion) => void;
  dismissNudge: (suggestion: NextTaskSuggestion) => void;
  teamId: string;
}

/**
 * Pure duration clamp — the D-10 non-blocking guarantee in code. Even if a
 * consumer passes `celebrationDurationMs={5000}`, the celebration is clamped to
 * < 1000 ms; a sub-200 ms flash (unreadable) is floored to 200 ms. Framework-free,
 * unit-testable, kit-extraction candidate.
 */

export const DEFAULT_CELEBRATION_MS = 800;
export const MIN_CELEBRATION_MS = 200;
/** Hard ceiling — strictly < 1000 ms (D-10). */
export const MAX_CELEBRATION_MS = 999;

export function clampDuration(ms?: number): number {
  return Math.min(
    Math.max(ms ?? DEFAULT_CELEBRATION_MS, MIN_CELEBRATION_MS),
    MAX_CELEBRATION_MS,
  );
}

"use client";

import * as React from "react";

import type { TeamFeedbackContextValue } from "../types";

export const TeamFeedbackContext =
  React.createContext<TeamFeedbackContextValue | null>(null);

/**
 * Read the current feedback state from a surrounding `TeamFeedbackLoopRoot`.
 * For hand-assembled layouts; throws if used outside a `Root`.
 */
export function useTeamFeedbackLoop(): TeamFeedbackContextValue {
  const ctx = React.useContext(TeamFeedbackContext);
  if (ctx === null) {
    throw new Error(
      "useTeamFeedbackLoop must be used within a <TeamFeedbackLoopRoot>.",
    );
  }
  return ctx;
}

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import { TeamFeedbackContext } from "../hooks/use-team-feedback-context";
import { clampDuration } from "../lib/clamp";
import type {
  FeedbackEvent,
  NextTaskSuggestion,
  TeamFeedbackContextValue,
  TeamFeedbackLoopHandle,
  TeamFeedbackLoopRootProps,
} from "../types";

// --- reduced-motion as an external store (SSR-safe; no set-state-in-effect) ---
function subscribeReducedMotion(callback: () => void): () => void {
  if (typeof window === "undefined" || !window.matchMedia) return () => {};
  const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
  mq.addEventListener("change", callback);
  return () => mq.removeEventListener("change", callback);
}
function getReducedMotionSnapshot(): boolean {
  if (typeof window === "undefined" || !window.matchMedia) return false;
  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
}
function getReducedMotionServerSnapshot(): boolean {
  return false;
}

// --- the single chokepoint reducer (both trigger paths funnel here, C3/C5) ---
type FeedbackState = {
  current: FeedbackEvent | null;
  epoch: number;
  dismissedTaskId: string | null;
};

type FeedbackAction =
  | { type: "open"; event: FeedbackEvent }
  | { type: "close" }
  | { type: "nudge-dismiss"; taskId: string }
  | { type: "nudge-rearm" };

function reducer(state: FeedbackState, action: FeedbackAction): FeedbackState {
  switch (action.type) {
    case "open":
      // Newest wins, never stack: one slot; bump epoch to re-arm the timer (C5).
      return { ...state, current: action.event, epoch: state.epoch + 1 };
    case "close":
      return state.current === null ? state : { ...state, current: null };
    case "nudge-dismiss":
      return { ...state, dismissedTaskId: action.taskId };
    case "nudge-rearm":
      return state.dismissedTaskId === null
        ? state
        : { ...state, dismissedTaskId: null };
    default:
      return state;
  }
}

/**
 * Tier B — headless provider. Owns the single current-event reducer that BOTH
 * the controlled `event` prop AND the imperative `celebrate()`/`dismiss()` handle
 * funnel into (C3), the < 1s auto-dismiss timer (clamped, D-10), the reduced-motion
 * read, the skip/Esc handlers, and the nudge dismissed/re-arm state. Holds NO
 * milestone/badge/task data — only "what to show right now". `onCelebrationDismiss`
 * fires ONLY on auto/skip/imperative-dismiss, never on a host-driven `event = null`
 * (controlled-echo). SSR-safe: `current` starts null, `reducedMotion` false on the
 * server → no animation/timer on first paint.
 */
export const TeamFeedbackLoopRoot = React.forwardRef<
  TeamFeedbackLoopHandle,
  TeamFeedbackLoopRootProps
>(function TeamFeedbackLoopRoot(
  {
    teamId,
    event,
    celebrationDurationMs,
    enableConfetti = false,
    renderCelebration,
    onCelebrationDismiss,
    nextTask,
    onNextTask,
    onNudgeDismiss,
    nudgePlacement = "inline",
    className,
    "aria-label": ariaLabel,
    children,
  },
  ref,
) {
  const [state, dispatch] = React.useReducer(reducer, {
    current: null,
    epoch: 0,
    dismissedTaskId: null,
  });
  // Destructure to locals so effect/memo deps are plain values (the exhaustive-deps
  // rule can't verify reducer-state member access is immutable).
  const { current, epoch, dismissedTaskId } = state;

  const reducedMotion = React.useSyncExternalStore(
    subscribeReducedMotion,
    getReducedMotionSnapshot,
    getReducedMotionServerSnapshot,
  );

  // --- stable callback refs (assigning ref.current in an effect is NOT setState) ---
  const onDismissRef = React.useRef(onCelebrationDismiss);
  const onAcceptRef = React.useRef(onNextTask);
  const onNudgeDismissRef = React.useRef(onNudgeDismiss);
  const currentRef = React.useRef<FeedbackEvent | null>(null);
  React.useEffect(() => {
    onDismissRef.current = onCelebrationDismiss;
    onAcceptRef.current = onNextTask;
    onNudgeDismissRef.current = onNudgeDismiss;
  }, [onCelebrationDismiss, onNextTask, onNudgeDismiss]);
  React.useEffect(() => {
    currentRef.current = current;
  }, [current]);

  // --- skip = user/imperative dismiss (fires the callback with reason "skip") ---
  const skip = React.useCallback(() => {
    const evt = currentRef.current;
    if (evt) onDismissRef.current?.(evt, "skip");
    dispatch({ type: "close" });
  }, []);

  // --- auto-dismiss timer: armed per open (keyed on current + epoch), cleared on close ---
  React.useEffect(() => {
    if (current === null) return;
    const ms = clampDuration(celebrationDurationMs);
    const id = window.setTimeout(() => {
      onDismissRef.current?.(current, "auto");
      dispatch({ type: "close" });
    }, ms);
    return () => window.clearTimeout(id);
  }, [current, epoch, celebrationDurationMs]);

  // --- controlled `event` prop → funnels into the reducer (undefined = imperative-only) ---
  const lastEventRef = React.useRef<FeedbackEvent | null | undefined>(undefined);
  React.useEffect(() => {
    if (event === undefined) return; // uncontrolled: imperative handle only
    if (event === lastEventRef.current) return;
    lastEventRef.current = event;
    if (event != null) {
      dispatch({ type: "open", event });
    } else {
      // Host-driven close — silent (no onCelebrationDismiss echo).
      dispatch({ type: "close" });
    }
  }, [event]);

  // --- Esc skips (additive, non-trapping) while a celebration is open ---
  React.useEffect(() => {
    if (current === null) return;
    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") skip();
    };
    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [current, skip]);

  // --- imperative handle (both paths land in the same reducer) ---
  React.useImperativeHandle(
    ref,
    () => ({
      celebrate(evt: FeedbackEvent) {
        dispatch({ type: "open", event: evt });
      },
      dismiss() {
        skip();
      },
    }),
    [skip],
  );

  // --- nudge: re-arm when a NEW taskId arrives ---
  const lastTaskIdRef = React.useRef<string | undefined>(undefined);
  React.useEffect(() => {
    const taskId = nextTask?.taskId;
    if (taskId === lastTaskIdRef.current) return;
    lastTaskIdRef.current = taskId;
    if (taskId != null) dispatch({ type: "nudge-rearm" });
  }, [nextTask?.taskId]);

  const acceptNudge = React.useCallback((s: NextTaskSuggestion) => {
    onAcceptRef.current?.(s);
  }, []);
  const dismissNudge = React.useCallback((s: NextTaskSuggestion) => {
    dispatch({ type: "nudge-dismiss", taskId: s.taskId });
    onNudgeDismissRef.current?.(s);
  }, []);

  const nudge =
    nextTask && nextTask.taskId !== dismissedTaskId ? nextTask : null;

  const contextValue = React.useMemo<TeamFeedbackContextValue>(
    () => ({
      current,
      reducedMotion,
      enableConfetti,
      renderCelebration,
      skip,
      nudge,
      nudgePlacement,
      acceptNudge,
      dismissNudge,
      teamId,
    }),
    [
      current,
      reducedMotion,
      enableConfetti,
      renderCelebration,
      skip,
      nudge,
      nudgePlacement,
      acceptNudge,
      dismissNudge,
      teamId,
    ],
  );

  return (
    <TeamFeedbackContext.Provider value={contextValue}>
      <div
        data-slot="team-feedback-loop"
        className={cn(className)}
        aria-label={ariaLabel}
      >
        {children}
      </div>
    </TeamFeedbackContext.Provider>
  );
});

"use client";

import * as React from "react";

import { useTeamFeedbackLoop } from "../hooks/use-team-feedback-context";
import { CelebrationOverlay } from "./celebration-overlay";

// The confetti value enters the graph ONLY here, via React.lazy — the default
// CSS flourish and `enableConfetti={false}` never load this chunk.
const ConfettiBurst = React.lazy(() => import("./confetti-burst"));

/**
 * Tier B — reads context and renders the current `FeedbackEvent` as a
 * `CelebrationOverlay`. Gates the lazy `ConfettiBurst` on
 * `enableConfetti && !reducedMotion && kind ∈ {milestone, badge}`, and preloads
 * its chunk at open time (so the burst is usually ready within the < 1s window;
 * if not, it's simply skipped — the CSS flourish already played). Renders nothing
 * when no event is current.
 */
export function TeamFeedbackCelebration() {
  const { current, reducedMotion, enableConfetti, renderCelebration, skip } =
    useTeamFeedbackLoop();

  const confettiEligible =
    enableConfetti &&
    !reducedMotion &&
    current != null &&
    (current.kind === "milestone" || current.kind === "badge");

  // Preload-on-arm: kick the import when an eligible event opens.
  React.useEffect(() => {
    if (confettiEligible) {
      void import("./confetti-burst").catch(() => {});
    }
  }, [confettiEligible]);

  if (current === null) return null;

  return (
    <CelebrationOverlay
      event={current}
      reducedMotion={reducedMotion}
      onSkip={skip}
      render={renderCelebration}
    >
      {confettiEligible ? (
        <React.Suspense fallback={null}>
          <ConfettiBurst />
        </React.Suspense>
      ) : null}
    </CelebrationOverlay>
  );
}

"use client";

import { useTeamFeedbackLoop } from "../hooks/use-team-feedback-context";
import { NextTaskNudge } from "./next-task-nudge";

/**
 * Tier B — reads context and renders the current nudge (suppressed while
 * dismissed). Independent of the celebration's < 1s lifecycle (C6) — a standing,
 * dismissible prompt. Renders nothing when there's no active suggestion.
 */
export function TeamFeedbackNudge() {
  const { nudge, nudgePlacement, acceptNudge, dismissNudge } =
    useTeamFeedbackLoop();

  if (nudge === null) return null;

  return (
    <NextTaskNudge
      suggestion={nudge}
      placement={nudgePlacement}
      onAccept={acceptNudge}
      onDismiss={dismissNudge}
    />
  );
}

"use client";

import { CheckCircle2, PartyPopper, Trophy, X } from "lucide-react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

import type { CelebrationOverlayProps, FeedbackEvent } from "../types";

const KIND_ICON: Record<FeedbackEvent["kind"], typeof PartyPopper> = {
  milestone: PartyPopper,
  badge: Trophy,
  "task-complete": CheckCircle2,
};

/**
 * Tier C — dumb, prop-driven celebration flourish. **The D-10 non-blocking
 * contract lives here:** the fixed wrapper AND the card are `pointer-events: none`
 * so clicks pass straight through to the board behind; the ONLY `pointer-events:
 * auto` element is the skip button. It never moves/traps focus, never renders a
 * work-halting scrim, and is a bottom-edge band, never a centered modal. Announces
 * via `role="status"` + `aria-live="polite"` (non-interrupting). Under reduced
 * motion the `reveal-up` entrance is dropped (static, instantly readable).
 * The `children` slot hosts the (already reduced-motion-gated) confetti burst.
 */
export function CelebrationOverlay({
  event,
  reducedMotion,
  onSkip,
  render,
  children,
  className,
}: CelebrationOverlayProps) {
  const Icon = KIND_ICON[event.kind];

  return (
    <div
      role="status"
      aria-live="polite"
      className={cn(
        "pointer-events-none fixed inset-x-0 bottom-6 z-50 flex justify-center px-4",
        className,
      )}
    >
      {children}
      <div
        className={cn(
          "pointer-events-none flex max-w-md items-start gap-3 rounded-xl border border-border bg-card px-4 py-3 text-card-foreground shadow-lg",
          !reducedMotion && "reveal-up",
        )}
      >
        {render ? (
          render(event)
        ) : (
          <>
            <span className="flex size-9 shrink-0 items-center justify-center rounded-lg bg-primary text-primary-foreground">
              <Icon className="size-5" aria-hidden />
            </span>
            <div className="flex min-w-0 flex-col gap-0.5">
              <p className="line-clamp-2 text-sm font-semibold text-foreground">
                {event.title}
              </p>
              {event.detail ? (
                <p className="line-clamp-2 text-xs text-muted-foreground">
                  {event.detail}
                </p>
              ) : null}
              {event.narrativeBeat ? (
                <p className="mt-1 font-mono text-[0.7rem] uppercase tracking-wide text-primary/80">
                  {event.narrativeBeat}
                </p>
              ) : null}
            </div>
          </>
        )}
        <Button
          variant="ghost"
          size="icon-sm"
          onClick={onSkip}
          aria-label="Dismiss celebration"
          className="pointer-events-auto shrink-0"
        >
          <X className="size-4" aria-hidden />
        </Button>
      </div>
    </div>
  );
}

"use client";

import { ArrowRight, X } from "lucide-react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

import type { NextTaskNudgeProps } from "../types";

/**
 * Tier C — dumb, prop-driven next-task nudge. A gentle, standing, dismissible
 * prompt — NEVER a modal. Accept + dismiss are real keyboard-operable `button`s;
 * dismiss is penalty-free (D-08). Long labels line-clamp with a `title` fallback;
 * corner placement caps its width so it never covers primary board actions.
 */
export function NextTaskNudge({
  suggestion,
  placement = "inline",
  onAccept,
  onDismiss,
  className,
}: NextTaskNudgeProps) {
  return (
    <div
      role="group"
      aria-label="Suggested next task"
      className={cn(
        "flex items-center gap-3 rounded-lg border border-border bg-card px-3 py-2 text-card-foreground",
        placement === "corner" &&
          "fixed bottom-4 right-4 z-40 max-w-xs shadow-lg",
        className,
      )}
    >
      <span className="flex size-7 shrink-0 items-center justify-center rounded-md bg-muted text-muted-foreground">
        <ArrowRight className="size-4" aria-hidden />
      </span>
      <div className="flex min-w-0 flex-col">
        <span className="text-[0.7rem] font-medium uppercase tracking-wide text-muted-foreground">
          Next up
        </span>
        <span
          className="line-clamp-2 text-sm text-foreground"
          title={suggestion.label}
        >
          {suggestion.label}
        </span>
      </div>
      <div className="ml-auto flex shrink-0 items-center gap-1">
        <Button size="sm" variant="secondary" onClick={() => onAccept(suggestion)}>
          Start
        </Button>
        <Button
          size="icon-sm"
          variant="ghost"
          onClick={() => onDismiss(suggestion)}
          aria-label="Dismiss suggestion"
        >
          <X className="size-4" aria-hidden />
        </Button>
      </div>
    </div>
  );
}

"use client";

// Dep-declaring import FIRST (the validate:meta-deps regex stops at the first
// `from`-import). This is the ONLY module that imports the confetti value — it is
// pulled solely via `React.lazy(() => import("./confetti-burst"))`, so the default
// CSS flourish and `enableConfetti={false}` never load its chunk.
import confetti from "canvas-confetti";
import * as React from "react";

/**
 * Tier C (lazy) — a one-shot, non-blocking confetti burst on mount. `canvas-confetti`
 * injects its own fixed, `pointer-events: none` canvas (inherently non-blocking, D-10)
 * and self-cleans. This component is never mounted under `prefers-reduced-motion`
 * (the celebration part gates it), and `disableForReducedMotion` is set as a
 * belt-and-suspenders. Renders no DOM. **DEFAULT export** for `React.lazy`.
 */
export default function ConfettiBurst() {
  React.useEffect(() => {
    // Signal-lime-forward palette (a canvas needs raw hex; not a UI token surface).
    confetti({
      particleCount: 90,
      spread: 72,
      startVelocity: 38,
      scalar: 0.9,
      origin: { y: 0.75 },
      colors: ["#c3f53c", "#a3e635", "#84cc16", "#ffffff"],
      disableForReducedMotion: true,
    });
  }, []);

  return null;
}
